import { useEffect, useState } from 'react'
import { listJobs, type JobCard } from '../api/hrflow'

interface Props {
  onNewSession: () => void
  onOpenJob: (job: JobCard) => void
}

function Logo() {
  return (
    <div className="flex items-center gap-2">
      <div className="flex h-7 w-7 items-center justify-center rounded-lg bg-violet-600">
        <svg viewBox="0 0 16 16" fill="none" className="h-4 w-4">
          <circle cx="8" cy="8" r="5.5" stroke="white" strokeWidth="1.5" />
          <path d="M8 5v3.5l2 1.5" stroke="white" strokeWidth="1.5" strokeLinecap="round" />
        </svg>
      </div>
      <span className="text-sm font-semibold tracking-tight text-zinc-100">
        First<span className="text-violet-400">Round</span>
      </span>
    </div>
  )
}

function SkillBadge({ name }: { name: string }) {
  return (
    <span className="rounded-md bg-zinc-800 px-2 py-0.5 text-[11px] font-medium text-zinc-400">
      {name}
    </span>
  )
}

function JobCardItem({ job, onClick }: { job: JobCard; onClick: () => void }) {
  const skills = job.skills?.slice(0, 4) ?? []
  const hasMore = (job.skills?.length ?? 0) > 4
  const date = job.updated_at ?? job.created_at
  const formattedDate = date
    ? new Date(date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'short', year: 'numeric' })
    : null

  return (
    <button
      onClick={onClick}
      className="group w-full text-left rounded-2xl border border-zinc-800 bg-zinc-900 px-5 py-4 transition-all hover:border-zinc-700 hover:bg-zinc-800/60 active:scale-[0.99]"
    >
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0 flex-1 space-y-1">
          <p className="truncate text-sm font-semibold text-zinc-100 group-hover:text-white">
            {job.name}
          </p>
          {job.location?.text && (
            <p className="flex items-center gap-1 text-xs text-zinc-500">
              <svg viewBox="0 0 16 16" fill="none" className="h-3 w-3 shrink-0">
                <path d="M8 1.5A4.5 4.5 0 0 1 12.5 6c0 3-4.5 8.5-4.5 8.5S3.5 9 3.5 6A4.5 4.5 0 0 1 8 1.5Z" stroke="currentColor" strokeWidth="1.3" />
                <circle cx="8" cy="6" r="1.5" stroke="currentColor" strokeWidth="1.3" />
              </svg>
              {job.location.text}
            </p>
          )}
        </div>
        <div className="flex shrink-0 flex-col items-end gap-2">
          {formattedDate && (
            <span className="text-[11px] text-zinc-600">{formattedDate}</span>
          )}
          <svg
            viewBox="0 0 16 16" fill="none"
            className="h-4 w-4 text-zinc-700 transition-all group-hover:translate-x-0.5 group-hover:text-violet-400"
          >
            <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </div>
      </div>
      {skills.length > 0 && (
        <div className="mt-3 flex flex-wrap gap-1.5">
          {skills.map(s => <SkillBadge key={s.name} name={s.name} />)}
          {hasMore && (
            <span className="rounded-md bg-zinc-800 px-2 py-0.5 text-[11px] font-medium text-zinc-600">
              +{(job.skills?.length ?? 0) - 4}
            </span>
          )}
        </div>
      )}
    </button>
  )
}

export default function RhHomePage({ onNewSession, onOpenJob }: Props) {
  const [jobs, setJobs] = useState<JobCard[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    listJobs()
      .then(setJobs)
      .catch(err => setError(err instanceof Error ? err.message : 'Erreur'))
      .finally(() => setLoading(false))
  }, [])

  return (
    <div className="min-h-screen text-zinc-50">
      <header className="fixed inset-x-0 top-0 z-10 flex h-14 items-center justify-between border-b border-zinc-800/60 bg-zinc-950/80 px-6 backdrop-blur-md">
        <Logo />
        <span className="text-xs text-zinc-600 hidden sm:block">Espace recruteur</span>
        <button
          onClick={onNewSession}
          className="flex items-center gap-2 rounded-xl bg-violet-600 px-4 py-2 text-xs font-semibold text-white transition-all hover:bg-violet-500 active:scale-[0.99]"
        >
          <svg viewBox="0 0 16 16" fill="none" className="h-3.5 w-3.5">
            <path d="M8 3v10M3 8h10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
          </svg>
          Nouvelle session
        </button>
      </header>

      <main className="flex min-h-screen items-start justify-center px-4 pb-16 pt-28">
        <div className="w-full max-w-xl space-y-6">

          <div className="space-y-1">
            <h1 className="text-2xl font-bold tracking-tight text-zinc-50">Sessions d'entretien</h1>
            <p className="text-sm text-zinc-500">
              {loading ? 'Chargement…' : `${jobs.length} offre${jobs.length !== 1 ? 's' : ''} sur le board`}
            </p>
          </div>

          {error && (
            <div className="flex items-start gap-3 rounded-xl border border-red-900/50 bg-red-950/30 px-4 py-3">
              <span className="text-red-400 text-sm">⚠</span>
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}

          {loading && (
            <div className="space-y-3">
              {[1, 2, 3].map(i => (
                <div key={i} className="h-20 animate-pulse rounded-2xl border border-zinc-800 bg-zinc-900" />
              ))}
            </div>
          )}

