          className="flex items-center gap-2 rounded-xl bg-violet-600 px-4 py-2 text-xs font-semibold text-white transition-all hover:bg-violet-500 active:scale-[0.99]"
        >
          <svg viewBox="0 0 16 16" fill="none" className="h-3.5 w-3.5">
            <path d="M8 3v10M3 8h10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
          </svg>
          Nouvelle session
        </button>
      </header>

      <main className="flex min-h-screen items-start justify-center px-4 pb-16 pt-28">
        <div className="w-full max-w-xl space-y-6">

          <div className="space-y-1">
            <h1 className="text-2xl font-bold tracking-tight text-zinc-50">Sessions d'entretien</h1>
            <p className="text-sm text-zinc-500">
              {loading ? 'Chargement…' : `${jobs.length} offre${jobs.length !== 1 ? 's' : ''} sur le board`}
            </p>
          </div>

          {error && (
            <div className="flex items-start gap-3 rounded-xl border border-red-900/50 bg-red-950/30 px-4 py-3">
              <span className="text-red-400 text-sm">⚠</span>
              <p className="text-sm text-red-300">{error}</p>
            </div>
          )}

          {loading && (
            <div className="space-y-3">
              {[1, 2, 3].map(i => (
                <div key={i} className="h-20 animate-pulse rounded-2xl border border-zinc-800 bg-zinc-900" />
              ))}
            </div>
          )}

          {!loading && jobs.length === 0 && !error && (
            <div className="rounded-2xl border border-dashed border-zinc-800 px-4 py-12 text-center">
              <p className="text-sm text-zinc-600">Aucune offre indexée sur ce board.</p>
              <button
                onClick={onNewSession}
                className="mt-4 text-sm font-medium text-violet-400 transition-colors hover:text-violet-300"
              >
                Créer la première session →
              </button>
            </div>
          )}

          {!loading && jobs.length > 0 && (
            <div className="space-y-3">
              {jobs.map(job => (
                <JobCardItem key={job.key} job={job} onClick={() => onOpenJob(job)} />
              ))}
            </div>
          )}

        </div>
      </main>
    </div>
  )
}

