              </button>
            </div>
          )}

          {!loading && jobs.length > 0 && (
            <div className="grid grid-cols-2 gap-3">
              {jobs.map(job => (
                <JobCardItem key={job.key} job={job} onClick={() => onOpenJob(job)} />
              ))}
            </div>
          )}

        </div>
      </main>
    </div>
  )
}

