                <p className="truncate text-[11px] text-zinc-500">{latestExp.company}</p>
              )}
            </div>
          </div>
        )}

        {/* Formation */}
        {latestEdu && !latestExp && (
          <div className="flex items-start gap-2 rounded-lg bg-zinc-800/50 px-3 py-2">
            <svg viewBox="0 0 16 16" fill="none" className="mt-0.5 h-3.5 w-3.5 shrink-0 text-zinc-500">
              <path d="M2 6l6-3 6 3-6 3-6-3Z" stroke="currentColor" strokeWidth="1.3" strokeLinejoin="round" />
