          <div className="flex flex-wrap gap-1">
            {skills.map(s => <SkillBadge key={s.name} name={s.name} />)}
            {hasMoreSkills && (
              <span className="rounded-md bg-zinc-800 px-2 py-0.5 text-[11px] font-medium text-zinc-600">
                +{(profile.skills?.length ?? 0) - 4}
              </span>
            )}
          </div>
        )}
      </div>
    </div>
