async def score_profiles(
    job_key: str,
    profile_keys: str = Query(..., description="Clés profils séparées par des virgules"),
    board_key: Optional[str] = Query(default=None),
    service: HrFlowService = Depends(get_hrflow_service),
) -> dict:
